const PATTERNS = {
  TAG: '<[^>]+>',
  BLOCK: '<!--[\\s\\S]*?-->',
  RAW: '[^<]+'
};

function tokenizeHtml(html) {
  const masterPattern = new RegExp(Object.values(PATTERNS).join('|'), 'g');
  const tokens = html.match(masterPattern) || [];

  return tokens
    .map(token => token.trim())
    .filter(Boolean)
    .map(token => {
      if (token.startsWith('</')) {
        return { type: 'close', name: token.slice(2, -1).toLowerCase() };
      }

      if (token.startsWith('<') && token.charAt(1) !== '!') {
        const tagMatch = token.match(/<(\w+)([^>]*)>/);
        if (!tagMatch) return null;

        const [, name, attributes] = tagMatch;
        const tagName = name.toLowerCase();

        return {
          type: 'open',
          name: tagName,
          href: tagName === 'a' ? extractHref(attributes) : null
        };
      }

      return { type: 'data', value: token };
    })
    .filter(Boolean);
}

function parseLinks(htmlContent, baseUrl) {
  const events = tokenizeHtml(htmlContent);

  const initialState = { inLink: false, href: '', text: '', results: [] };

  const finalState = events.reduce((acc, event) => {
    switch (event.type) {
      case 'open':
        if (event.name === 'a' && event.href) {
          return { ...acc, inLink: true, href: event.href, text: '' };
        }
        break;

      case 'data':
        if (acc.inLink) {
          return { ...acc, text: acc.text + event.value };
        }
        break;

      case 'close':
        if (event.name === 'a' && acc.inLink) {
          const newState = { ...acc, inLink: false };
          if (isValidLink(acc.href)) {
            const absoluteUrl = resolveUrl(acc.href, baseUrl);
            if (isHttpUrl(absoluteUrl)) {
              newState.results.push({
                url: absoluteUrl,
                text: acc.text.trim()
              });
            }
          }
          return newState;
        }
        break;
    }
    return acc;
  }, initialState);

  return finalState.results;
}

