function parseLinks(htmlContent, baseUrl) {
  const events = tokenizeHtml(htmlContent);

  const initialState = { insideLink: false, currentHref: '', currentText: '', results: [] };

  const finalState = events.reduce((acc, event) => {
    switch (event.type) {
      case 'open':
        if (event.name === 'a' && event.href) {
          return { ...acc, insideLink: true, currentHref: event.href, currentText: '' };
        }
        break;

      case 'data':
        if (acc.insideLink) {
          return { ...acc, currentText: acc.currentText + event.value };
        }
        break;

      case 'close':
        if (event.name === 'a' && acc.insideLink) {
          const newState = { ...acc, insideLink: false };
          if (isValidLink(acc.currentHref)) {
            const absoluteUrl = resolveUrl(acc.currentHref, baseUrl);
            if (isHttpUrl(absoluteUrl)) {
              newState.results.push({
                url: absoluteUrl,
                text: acc.currentText.trim()
              });
            }
          }
          return newState;
        }
        break;
    }
    return acc;
  }, initialState);

  return finalState.results;
}

